window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2009>1>a","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"a","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study specimens A, B and C carefully and use them to answer questions (a) to (d).    State the habitats specimens A, Band C.","images":[],"marking_scheme":"A/Water lettuce - On the surface of ponds/lakes/streams.    B/Cactus-Deserts/savannahs/dry/arid regions/along the sea coast.    C/Talinum- Farmland/gardens/wet lands/waste land/any other appropriate habitat.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>1>b>i","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"i","group":"","topic":"EVOLUTION : ADAPTATION FOR SURVIVAL~~EVOLUTION : STRUCTURAL ADAPTATION","question":"State two observable features each of specimens A,B and C.","images":[],"marking_scheme":"The observable features of specimen A (Water lettuce)  -It has broad aerial leaves  -It has numerous adventitious roots  -It stem and leaves are green  -It has stolon (Slender Stem)  -The surface of the leaves contains hairs  -The leaves have rosette arrangement  The leaves are spongy  The observable features of Specimen B (cactus).  -The leaves are modified into spines   -It has succulent stems  -The stem has thick waxy cuticle  -The stem is flattened  -It has green stem  The observable features of specimen C(Water leaf or Talinum)  -It has well developed taproot system  -It has numerous green leaves  -It has swollen tap root  -It has upright or erect stem","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>1>b>ii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State how the features in 1(b)(i) adapt the specimens to their habitats.","images":[],"marking_scheme":"Specimen A (Water lettuce)  -The broad aerial leaves and rosette arrangement of leaves makes it bouyant to receive maximum sunlight for photosynthesis  -The numerous adventitious roots aids absorption of of water and mineral salt It also enhances floatation.  -The leaves are green for photosynthesis.  -The slender stems or stolon offer maximum resistance to watercurrents.  -The hairy leaves prevent water from blocking the stomata and aids photosynthesis and respiration  -The buds on the stem is for vegetative propagation.  -The spongy leaves aids bouyancy or floating  The Features of Specimen B to its Adaptation  -It has flatened stems to receive maximum light  -The leaves modified into spines to prevent water loss  -It has its leaves modified into spines to prevent water loss  -It has succulent stems for water storage  -It possesses thick waxy cuticle on the stem to reduce water loss by transpiration  -It has green stem for photosynthesis  The Features of Specimen C to its Adaptation  -It has well developed root system for anchorage and water absorption  -It possesses numerous green leaves for photosynthesis  -The erect stem hold the leaves to receive maximum sunlight  -It has swollen taproot for storage","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>1>c","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"c","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State three Observable differences between specimens A and C.","images":[],"marking_scheme":"A/Water lettuceC/Talinum sp/Waterleaf/Amarantus spAdventitious root systemTap root systemHorizontal stem/stolonErect stemHairs on leavesHairless leaves/smooth surfaceLeaves borne in a rosetteLeaves arise singly on the stemAbsence of branchesBranches presentFlowers absentFlowers present","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>1>d","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"d","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Make a drawing 8- 10cm long of specimen C and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of specimen C/Talinum sp/Amaranthus sp","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>2>a","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"a","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"A farmer applied different concentrations off cytokinins to his pineapple plants and observed the development of new shoots Over a period of time.    The result of his observation is shown below.    S/No.Concentration of Cytokinin(mg/litre)Number of new shoots10221532843.512541864.5257520861097.581086119512105  Plot a graph to show the relationship between cytokinin concentration and shoot development.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2009>2>b","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"b","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"Use the graph to describe the effect of cytokinin concentration on shoot development.","images":[],"marking_scheme":"Description of graph: Initially the rate of production of new pineapple shoots increases; with Increased concentration of cytokinin    -Shoot development reaches its peak at optimum concentration of cytokinin/4.5mg/l    - Above this concentration, shoot development declines/decrease.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>2>c","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"What advice should be given to the farmer based on the results from the graph?","images":[],"marking_scheme":"Cytokinn should not be applied beyond a concentration of 4.5mg/litres for optimum shoot development","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>2>d>i","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"List (2) two substances in plants which have similar effect as cytokinins.","images":[],"marking_scheme":"-Auxin  -Ethylene","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>2>d>ii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"List (2) two substances in animals which have similar effect as cytokinins","images":[],"marking_scheme":"-Pituitary growth home  -Follicle stimulating hormone  -thyroxin","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>a","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"a","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study carefully specimens H, Jand K and use them to answer questions 4(a) to 4(d).    State the habitat of specimen J.","images":[],"marking_scheme":"Frogs Pond/Stream/Fresh water swamps/Swamps/River banks.    Toads- Wet damp places/under leaves/small holes.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>b>i","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State five observable features of specimen J;","images":[],"marking_scheme":"-Webbed digits Streamlined body   - bulging eyes above the head  - Nostril above the head   - Nictitating membrane   - Body odour   - Short/stout fore limb  - Long (strong) hind limb   - Moist/warty skin   - poisonous gland   - Long tongue attached to front lip.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>b>ii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State how the features in 4(b)(i) adapt specimen J to its habitat.","images":[],"marking_scheme":"-Webbed digits for swimming/paddling in water Streamlined body for easy movement in water  - bulging eyes to see above water when body is submerged  -Position of nostril above the head enables animal ans get atmosphere air while swimming.  -Nictitating membranes protect eyes from foreign bodies while in water/cleans eye surface.  -Body color blends with surrounding for camouflage.  -Short/stout act as shock absorber/ for landing.  - Long strong hind limbs for hopping on land.  - warty skin prevents evaporation from body/moist skin provides surface for gaseous exchange.  - Poisonous gland for protection against predators.  - Long tongue attached to front lip for easy catching of prey.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>c>i","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"List two differences between specimens H and J.","images":[],"marking_scheme":"H/LungJ/ToadBright red/pinkDark grey/brownOrganOrganism","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>c>ii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State three similarities between specimen H and the skin of specimen J.","images":[],"marking_scheme":"-Thin surface membranes  -Moist surface   -Large surface area  - Their body is richly supplied with blood vessels/highly vascularized.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>c>iii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"iii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State how the similar features named in 4(C)(ii) above adapt specimen H for its functions.","images":[],"marking_scheme":"- Thin membranes allow easy diffusion of oxygen and carbon dioxide/exchange of gases.  -Moist surface for dissolving of gases/carbon dioxide and oxygen   - Abundant blood vessels for transport of respiratory gases  -Large surface area for diffusion/exchange gases.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>d>i","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Classify specimen K into its phylum and class.","images":[],"marking_scheme":"Classification of K/Maize leaf: Phylum/ Angiospermophyta.     Class- Monocotylenonae","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>d>ii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Give three reasons for placing specimen K in its class.","images":[],"marking_scheme":"-Long narrow blade   - Parallel venation   - Presence of leaf sheath","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2009>3>d>iii","subject":"Biology Practical","year":"2009","type":"Practical","sub_label":"iii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"List three observable features of specimen K and state how these features adapt it to its mode of life.","images":[],"marking_scheme":"-thin/fat blade; to facilitate diffusion or gases.   - Green color chlorophyll; to absorb sunlight for photosynthesis.  -Large surface area; to absorb maximum sunlight  -Presence of veins; for transport of water/manufactured food.","marks":"1","difficulty":"2"}];